class OrchestratorAdapter(RuntimeAdapter):
    adapter_kind: str = 'orchestrator'

    def prepare_turn(self, *, model, system_prompt, dynamic_messages, grammar=None, todo=None, deltas=None):
        prepared = self.prepare(model=model, messages=dynamic_messages, system=system_prompt, tool_compatible=False, grammar=grammar, todo=todo, deltas=deltas)
        chat_messages = _system_to_messages(prepared.body.get('system')) + prepared.body.get('messages', [])
        return chat_messages, prepared
